+
+function styleRecords() {
+  return [
+    {value: 'no-change' as const, description: 'Leaves this syntax unchanged'},
+    {value: 'markdown' as const, description: 'Uses Markdown link syntax'},
+    {value: 'wiki' as const, description: 'Uses Obsidian wiki link syntax'},
+  ];
+}
+
+function convertWikiLinksToMarkdown(text: string, options: LinkStyleOptions): string {
+  return text.replace(/(!?)\\[\\[([^\\]\
|]+)(?:\\|([^\\]\
|]+))?\\]\\]/g, (match, bang: string, target: string, display: string | undefined) => {
+    const isImage = bang === '!';
+    if ((isImage ? options.imageStyle : options.linkStyle) !== 'markdown') {
+      return match;
+    }
+
+    const label = isImage && isEmbedSize(display) ? target : (display ?? defaultHeadingDisplay(target));
+    return `${isImage ? '!' : ''}[${label}](${target})`;
+  });
+}
+
+function convertMarkdownLinksToWiki(text: string, options: LinkStyleOptions): string {
+  let output = '';
+  let index = 0;
+
+  while (index < text.length) {
+    const parsed = parseMarkdownLink(text, index);
+    if (!parsed) {
+      output += text[index++];
+      continue;
+    }
+
+    const style = parsed.isImage ? options.imageStyle : options.linkStyle;
+    if (style !== 'wiki' || parsed.target.includes('://')) {
+      output += parsed.source;
+    } else {
+      const display = unescapeMarkdown(parsed.label);
+      const target = unescapeMarkdown(parsed.target);
+      const omitDisplay = display === target || display === defaultHeadingDisplay(target);
+      const wikiDisplay = parsed.isImage ? (display === '' || display === target ? '' : `|${display}`) : (omitDisplay ? '' : `|${display}`);
+      output += `${parsed.isImage ? '!' : ''}[[${target}${wikiDisplay}]]`;
+    }
+    index = parsed.end;
+  }
+
+  return output;
+}
+
+type ParsedMarkdownLink = {
+  source: string,
+  isImage: boolean,
+  label: string,
+  target: string,
+  end: number,
+};
+
+function parseMarkdownLink(text: string, start: number): ParsedMarkdownLink | null {
+  const isImage = text[start] === '!';
+  const labelStart = isImage ? start + 1 : start;
+  if (text[labelStart] !== '[' || (start > 0 && isEscaped(text, start))) {
+    return null;
+  }
+
+  const labelEnd = findClosingBracket(text, labelStart);
+  if (labelEnd === null || text[labelEnd + 1] !== '(') {
+    return null;
+  }
+
+  const destinationEnd = findClosingParenthesis(text, labelEnd + 1);
+  if (destinationEnd === null) {
+    return null;
+  }
+
+  const label = text.slice(labelStart + 1, labelEnd);
+  const destination = parseDestination(text.slice(labelEnd + 2, destinationEnd));
+  if (label.includes('\
') || destination === null) {
+    return null;
+  }
+
+  return {
+    source: text.slice(start, destinationEnd + 1),
+    isImage,
+    label,
+    target: destination,
+    end: destinationEnd + 1,
+  };
+}
+
+function findClosingBracket(text: string, start: number): number | null {
+  let depth = 0;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\
') {
+      return null;
+    }
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '[') {
+      depth++;
+    } else if (text[index] === ']' && --depth === 0) {
+      return index;
+    }
+  }
+  return null;
+}
+
+function findClosingParenthesis(text: string, start: number): number | null {
+  let depth = 0;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\
') {
+      return null;
+    }
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '(') {
+      depth++;
+    } else if (text[index] === ')' && --depth === 0) {
+      return index;
+    }
+  }
+  return null;
+}
+
+function parseDestination(value: string): string | null {
+  const trimmed = value.trim();
+  if (trimmed === '') {
+    return null;
+  }
+
+  if (trimmed.startsWith('<')) {
+    const closing = findUnescapedCharacter(trimmed, '>', 1);
+    if (closing === null || trimmed.slice(closing + 1).trim() !== '') {
+      return null;
+    }
+    return trimmed.slice(1, closing);
+  }
+
+  return hasUnescapedWhitespace(trimmed) ? null : trimmed;
+}
+
+function findUnescapedCharacter(value: string, character: string, start: number): number | null {
+  for (let index = start; index < value.length; index++) {
+    if (value[index] === '\\\') {
+      index++;
+    } else if (value[index] === character) {
+      return index;
+    }
+  }
+  return null;
+}
+
+function hasUnescapedWhitespace(value: string): boolean {
+  for (let index = 0; index < value.length; index++) {
+    if (value[index] === '\\\') {
+      index++;
+    } else if (/\\s/.test(value[index])) {
+      return true;
+    }
+  }
+  return false;
+}
+
+function isEscaped(text: string, index: number): boolean {
+  let slashCount = 0;
+  for (let cursor = index - 1; cursor >= 0 && text[cursor] === '\\\'; cursor--) {
+    slashCount++;
+  }
+  return slashCount % 2 === 1;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1) {
+    return target;
+  }
+
+  const page = target.slice(0, headingIndex);
+  const heading = target.slice(headingIndex + 1);
+  return page === '' ? heading : `${page} > ${heading}`;
+}
+
+function isEmbedSize(display: string | undefined): boolean {
+  return display !== undefined && /^\\d+(?:x\\d+)?$/.test(display);
+}
