import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';

type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle: LinkStyleValue = 'no-change';
  imageStyle: LinkStyleValue = 'no-change';
}

const obsidianCommentIgnore = {
  replaceAction: /%%[\s\S]*?%%/g,
  placeholder: '{OBSIDIAN_COMMENT_PLACEHOLDER}',
};

@RuleBuilder.register
export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
  constructor() {
    super({
      nameKey: 'rules.link-style.name',
      descriptionKey: 'rules.link-style.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [
        IgnoreTypes.yaml,
        IgnoreTypes.code,
        IgnoreTypes.inlineCode,
        IgnoreTypes.math,
        IgnoreTypes.inlineMath,
        IgnoreTypes.html,
        IgnoreTypes.templaterCommand,
        IgnoreTypes.table,
        obsidianCommentIgnore,
      ],
    });
  }

  get OptionsClass(): new () => LinkStyleOptions {
    return LinkStyleOptions;
  }

  apply(text: string, options: LinkStyleOptions): string {
    if (options.linkStyle === 'markdown' || options.imageStyle === 'markdown') {
      text = convertWikiLinksToMarkdown(text, options);
    }

    if (options.linkStyle === 'wiki' || options.imageStyle === 'wiki') {
      text = convertMarkdownLinksToWiki(text, options);
    }

    return text;
  }

  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Wiki links and embeds can use Markdown syntax',
        before: dedent`
          [[t]]
          [[t|d]]
          [[p#h]]
          [[#h]]
          ![[f.png|300x200]]
        `,
        after: dedent`
          [t](t)
          [d](t)
          [p > h](p#h)
          [h](#h)
          ![f.png](f.png)
        `,
        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
      }),
      new ExampleBuilder({
        description: 'Inline Markdown links and images can use wiki syntax',
        before: dedent`
          [t](t)
          [d](t)
          [p > h](p#h)
          ![alt](f.png)
        `,
        after: dedent`
          [[t]]
          [[t|d]]
          [[p#h]]
          ![[f.png|alt]]
        `,
        options: {linkStyle: 'wiki', imageStyle: 'wiki'},
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
    return [
      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
        OptionsClass: LinkStyleOptions,
        nameKey: 'rules.link-style.link-style.name',
        descriptionKey: 'rules.link-style.link-style.description',
        optionsKey: 'linkStyle',
        records: styleRecords(),
      }),
      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
        OptionsClass: LinkStyleOptions,
        nameKey: 'rules.link-style.image-style.name',
        descriptionKey: 'rules.link-style.image-style.description',
        optionsKey: 'imageStyle',
        records: styleRecords(),
      }),
    ];
  }
}

function styleRecords() {
  return [
    {value: 'no-change' as const, description: 'Leaves this syntax unchanged'},
    {value: 'markdown' as const, description: 'Uses Markdown link syntax'},
    {value: 'wiki' as const, description: 'Uses Obsidian wiki link syntax'},
  ];
}

function convertWikiLinksToMarkdown(text: string, options: LinkStyleOptions): string {
  return text.replace(/(!?)\[\[([^\]\n|]+)(?:\|([^\]\n|]+))?\]\]/g, (match, bang: string, target: string, display: string | undefined) => {
    const isImage = bang === '!';
